import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Button, Modal, Form, Badge, InputGroup } from 'react-bootstrap';
import { useParams } from 'react-router-dom';
import { courseService } from '../services/courseService';
import { resourceService } from '../services/resourceService';
import { Course, Resource } from '../types';
import Loading from '../components/Loading';
import ErrorMessage from '../components/ErrorMessage';
import ResourceCard from '../components/ResourceCard';
import FileUpload from '../components/FileUpload';

const CourseDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [course, setCourse] = useState<Course | null>(null);
  const [resources, setResources] = useState<Resource[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showUploadModal, setShowUploadModal] = useState(false);
  
  // Upload form state
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [link, setLink] = useState('');
  const [resourceTitle, setResourceTitle] = useState('');
  const [resourceDescription, setResourceDescription] = useState('');
  const [tags, setTags] = useState('');
  const [uploading, setUploading] = useState(false);

  // Filter state
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState('');

  useEffect(() => {
    if (id) {
      fetchData();
    }
  }, [id]);

  const fetchData = async () => {
    if (!id) return;
    try {
      const [courseData, resourcesData] = await Promise.all([
        courseService.getById(id),
        resourceService.getByCourse(id)
      ]);
      setCourse(courseData);
      setResources(resourcesData);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to load course data');
    } finally {
      setLoading(false);
    }
  };

  const handleFileSelect = (file: File | null, selectedLink: string) => {
    setSelectedFile(file);
    setLink(selectedLink);
  };

  const handleUpload = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!id) return;

    setUploading(true);
    try {
      const formData = new FormData();
      formData.append('title', resourceTitle);
      formData.append('description', resourceDescription);
      formData.append('courseId', id);
      formData.append('tags', JSON.stringify(tags.split(',').map(t => t.trim()).filter(t => t)));

      if (selectedFile) {
        formData.append('file', selectedFile);
      } else if (link) {
        formData.append('link', link);
      }

      await resourceService.upload(formData);
      setShowUploadModal(false);
      resetForm();
      fetchData();
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to upload resource');
    } finally {
      setUploading(false);
    }
  };

  const resetForm = () => {
    setResourceTitle('');
    setResourceDescription('');
    setTags('');
    setSelectedFile(null);
    setLink('');
  };

  const handleSearch = async () => {
    if (!id) return;
    try {
      const filtered = await resourceService.getByCourse(id, {
        search: searchQuery || undefined,
        fileType: filterType || undefined
      });
      setResources(filtered);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to search resources');
    }
  };

  if (loading) {
    return <Loading />;
  }

  if (!course) {
    return (
      <Container className="py-4">
        <ErrorMessage message="Course not found" />
      </Container>
    );
  }

  return (
    <Container className="py-4">
      <div className="mb-4">
        <a href="/" className="text-decoration-none">← Back to Dashboard</a>
      </div>

      <Card className="mb-4">
        <Card.Body>
          <Card.Title>{course.name}</Card.Title>
          <Card.Subtitle className="mb-2 text-muted">{course.code}</Card.Subtitle>
          <Card.Text>{course.description}</Card.Text>
        </Card.Body>
      </Card>

      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="mb-0">Resources ({resources.length})</h3>
        <Button variant="primary" onClick={() => setShowUploadModal(true)}>
          Upload Resource
        </Button>
      </div>

      <ErrorMessage message={error} onClose={() => setError('')} />

      {/* Search and Filter */}
      <Row className="mb-4">
        <Col md={6}>
          <InputGroup>
            <Form.Control
              type="text"
              placeholder="Search resources..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
            />
          </InputGroup>
        </Col>
        <Col md={3}>
          <Form.Select value={filterType} onChange={(e) => setFilterType(e.target.value)}>
            <option value="">All Types</option>
            <option value="application/pdf">PDF</option>
            <option value="application/msword">Word</option>
            <option value="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet">Excel</option>
            <option value="image">Images</option>
            <option value="link">Links</option>
          </Form.Select>
        </Col>
        <Col md={3}>
          <Button variant="outline-primary" onClick={handleSearch} className="w-100">
            Search
          </Button>
        </Col>
      </Row>

      {resources.length === 0 ? (
        <Card className="text-center p-4">
          <Card.Body>
            <Card.Title>No resources yet</Card.Title>
            <Card.Text>Be the first to upload a study resource!</Card.Text>
          </Card.Body>
        </Card>
      ) : (
        resources.map((resource) => (
          <ResourceCard key={resource.id} resource={resource} />
        ))
      )}

      {/* Upload Modal */}
      <Modal show={showUploadModal} onHide={() => setShowUploadModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Upload Resource</Modal.Title>
        </Modal.Header>
        <Form onSubmit={handleUpload}>
          <Modal.Body>
            <Form.Group className="mb-3">
              <Form.Label>Title</Form.Label>
              <Form.Control
                type="text"
                placeholder="Resource title"
                value={resourceTitle}
                onChange={(e) => setResourceTitle(e.target.value)}
                required
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Description</Form.Label>
              <Form.Control
                as="textarea"
                rows={2}
                placeholder="Optional description"
                value={resourceDescription}
                onChange={(e) => setResourceDescription(e.target.value)}
              />
            </Form.Group>

            <FileUpload onFileSelect={handleFileSelect} />

            <Form.Group className="mb-3">
              <Form.Label>Tags (comma-separated)</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., lecture, chapter, exam"
                value={tags}
                onChange={(e) => setTags(e.target.value)}
              />
            </Form.Group>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={() => setShowUploadModal(false)}>
              Cancel
            </Button>
            <Button variant="primary" type="submit" disabled={uploading}>
              {uploading ? 'Uploading...' : 'Upload'}
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </Container>
  );
};

export default CourseDetail;
